import{_ as e,o as i,c as a,ao as o}from"./chunks/framework.C3EQGe-O.js";const p=JSON.parse('{"title":"calibs.csv — your calibration videos","description":"","frontmatter":{},"headers":[],"relativePath":"calibs.md","filePath":"calibs.md","lastUpdated":null}'),s={name:"calibs.md"};function r(n,t,l,d,h,c){return i(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="calibs.csv-—-your-calibration-videos" tabindex="-1">calibs.csv — your calibration videos <a class="header-anchor" href="#calibs.csv-—-your-calibration-videos" aria-label="Permalink to &quot;calibs.csv — your calibration videos {#calibs.csv-—-your-calibration-videos}&quot;">​</a></h1><p><code>calibs.csv</code> describes your <strong>calibrations</strong>: how Fromage converts pixels in each camera view into real-world coordinates on the arena floor. One row per calibration. Every run in <code>runs.csv</code> points at one of these rows through its <code>calibration_id</code>.</p><p>Not sure about the general formatting rules (timestamps, coordinates, blank cells)? See <a href="/Fromage.jl/dev/data-folder#Rules-both-csv-files-share">the data folder</a> first.</p><h2 id="The-four-kinds-of-calibration" tabindex="-1">The four kinds of calibration <a class="header-anchor" href="#The-four-kinds-of-calibration" aria-label="Permalink to &quot;The four kinds of calibration {#The-four-kinds-of-calibration}&quot;">​</a></h2><p>Every calibration is anchored to a video file of the arena. There are four kinds, selected with the <code>type</code> column:</p><ul><li><p><strong><code>video</code></strong> (the default): a video of a checkerboard being moved around the arena, then laid flat on the arena floor. Yields a full calibration — lens distortion, perspective, and scale. <strong>This is the one you&#39;ll usually want.</strong></p></li><li><p><strong><code>only_scale</code></strong>: no checkerboard; you supply a fixed scale (real-world units per pixel). No distortion or perspective correction — appropriate for e.g. distortion-free footage filmed straight down.</p></li><li><p><strong><code>matlab</code></strong>: a calibration you already made with MATLAB&#39;s Camera Calibrator app, supplied as a <code>.mat</code> file. The camera model — intrinsics, lens distortion, and the extrinsic poses — is read from the file instead of being fit from a video.</p></li><li><p><strong><code>apriltag</code></strong>: drone (moving-camera) footage with four (or more) coplanar AprilTags visible on the arena floor. Instead of a fixed image→arena map, every run frame is registered to a shared reference — built from the <code>extrinsic</code> frame — so the drone&#39;s motion is cancelled and the target comes out in metric ground coordinates. The tags must stay in the same physical place across the calibration and all its runs.</p></li></ul><h2 id="What-makes-a-good-calibration-video" tabindex="-1">What makes a good calibration video <a class="header-anchor" href="#What-makes-a-good-calibration-video" aria-label="Permalink to &quot;What makes a good calibration video {#What-makes-a-good-calibration-video}&quot;">​</a></h2><p>For the usual <code>video</code> type:</p><ul><li><p>Film the checkerboard at the same location and with the exact same camera settings (zoom, resolution, mounting) as the runs it will calibrate.</p></li><li><p>During [<code>start</code>, <code>stop</code>], move and tilt the board through the volume where the animal will be — variety of poses is what constrains the lens model.</p></li><li><p>Then lay the board flat on the arena floor and note that timestamp — that&#39;s your <code>extrinsic</code>.</p></li><li><p>Keep the full board visible and unobstructed; avoid motion blur (move slowly) and glare.</p></li></ul><h2 id="Columns-for-type-video" tabindex="-1">Columns for <code>type = video</code> <a class="header-anchor" href="#Columns-for-type-video" aria-label="Permalink to &quot;Columns for `type = video` {#Columns-for-type-video}&quot;">​</a></h2><p>Required:</p><table tabindex="0"><thead><tr><th style="text-align:right;">column</th><th style="text-align:right;">description</th></tr></thead><tbody><tr><td style="text-align:right;"><code>calibration_id</code></td><td style="text-align:right;">a unique name for this calibration; referenced from <code>runs.csv</code>.</td></tr><tr><td style="text-align:right;"><code>file</code></td><td style="text-align:right;">the video file name, including extension.</td></tr><tr><td style="text-align:right;"><code>extrinsic</code></td><td style="text-align:right;">timestamp of a frame where the checkerboard lies <strong>flat on the arena floor</strong>. This frame anchors the mapping between the image and the arena surface, so make sure the full board is clearly visible in it.</td></tr></tbody></table><p>Optional:</p><table tabindex="0"><thead><tr><th style="text-align:right;">column</th><th style="text-align:right;">default</th><th style="text-align:right;">description</th></tr></thead><tbody><tr><td style="text-align:right;"><code>start</code>, <code>stop</code></td><td style="text-align:right;">—</td><td style="text-align:right;">the time window during which the checkerboard is being moved around (tilted, shifted) for the internal camera calibration. Provide both or neither. The window must be long enough to contain at least 3 sampled frames with a detectable checkerboard (see <code>temporal_step</code>). When <strong>both</strong> are omitted the calibration is fit from the single <code>extrinsic</code> frame alone, and lens distortion is disregarded — only appropriate for distortion-free lenses; otherwise film a calibration window and provide it.</td></tr><tr><td style="text-align:right;"><code>checker_size</code></td><td style="text-align:right;"><code>4</code></td><td style="text-align:right;">side length of a single checker square, in the real-world unit of your choice (e.g. cm). <strong>The resulting track coordinates come out in this unit.</strong></td></tr><tr><td style="text-align:right;"><code>n_corners</code></td><td style="text-align:right;"><code>&quot;(7, 10)&quot;</code></td><td style="text-align:right;">number of <em>internal</em> corners of the checkerboard along its two sides (a board of 8 × 11 squares has 7 × 10 internal corners); each must be at least 2.</td></tr><tr><td style="text-align:right;"><code>temporal_step</code></td><td style="text-align:right;"><code>2.0</code></td><td style="text-align:right;">sample one frame every <code>temporal_step</code> seconds within [<code>start</code>, <code>stop</code>]. E.g. a 30-second window at the default yields 16 candidate frames. Ignored without a calibration window.</td></tr><tr><td style="text-align:right;"><code>center</code></td><td style="text-align:right;">—</td><td style="text-align:right;"><code>&quot;(x, y)&quot;</code> pixel coordinate of the arena&#39;s center. Becomes the <strong>origin</strong> of the real-world coordinate system, and doubles as the default starting location for this calibration&#39;s runs.</td></tr><tr><td style="text-align:right;"><code>north</code></td><td style="text-align:right;">—</td><td style="text-align:right;"><code>&quot;(x, y)&quot;</code> pixel coordinate of a point lying due north of <code>center</code>. Rotates the real-world coordinates so that north is consistent across calibrations. Requires <code>center</code>.</td></tr><tr><td style="text-align:right;"><code>blur</code></td><td style="text-align:right;"><code>1</code></td><td style="text-align:right;">Gaussian blur (sigma, in pixels) applied to frames before corner detection; helps with noisy/sharpened footage. <code>0</code> disables.</td></tr><tr><td style="text-align:right;"><code>radial_parameters</code></td><td style="text-align:right;"><code>1</code></td><td style="text-align:right;">number of radial lens-distortion coefficients to fit (1–3). More isn&#39;t automatically better — use 2–3 only for strongly distorting (e.g. fisheye) lenses. Ignored without a calibration window.</td></tr><tr><td style="text-align:right;"><code>path</code></td><td style="text-align:right;"><code>.</code></td><td style="text-align:right;">folder containing <code>file</code>, relative to the location of the csv file.</td></tr><tr><td style="text-align:right;"><code>aspect</code></td><td style="text-align:right;">read from video</td><td style="text-align:right;">pixel aspect ratio; only override for anamorphic footage that misreports it.</td></tr><tr><td style="text-align:right;"><code>yadif</code></td><td style="text-align:right;">read from video</td><td style="text-align:right;"><code>true</code> to deinterlace interlaced footage; detected automatically, override to force.</td></tr><tr><td style="text-align:right;"><code>type</code></td><td style="text-align:right;"><code>video</code></td><td style="text-align:right;">see above.</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Count the <em>internal</em> corners</p><p><code>n_corners</code> counts where four squares meet, not the squares themselves. A board of 8 × 11 squares has 7 × 10 internal corners.</p></div><h2 id="Columns-for-type-only_scale" tabindex="-1">Columns for <code>type = only_scale</code> <a class="header-anchor" href="#Columns-for-type-only_scale" aria-label="Permalink to &quot;Columns for `type = only_scale` {#Columns-for-type-only_scale}&quot;">​</a></h2><p>Required: <code>calibration_id</code>, <code>file</code>, <code>extrinsic</code> (a timestamp of any representative frame), and:</p><table tabindex="0"><thead><tr><th style="text-align:right;">column</th><th style="text-align:right;">description</th></tr></thead><tbody><tr><td style="text-align:right;"><code>scale</code></td><td style="text-align:right;">real-world units per pixel (e.g. cm/pixel).</td></tr></tbody></table><p>Optional: <code>path</code>, <code>center</code>, <code>north</code>, <code>aspect</code> — same meaning as above.</p><h2 id="Columns-for-type-matlab" tabindex="-1">Columns for <code>type = matlab</code> <a class="header-anchor" href="#Columns-for-type-matlab" aria-label="Permalink to &quot;Columns for `type = matlab` {#Columns-for-type-matlab}&quot;">​</a></h2><p>Required: <code>calibration_id</code>, <code>file</code> (a video of the arena from the same camera — its frame size is cross-checked against the <code>.mat</code>&#39;s <code>ImageSize</code>), <code>extrinsic</code> (a timestamp of any representative frame, used for the diagnostics), and:</p><table tabindex="0"><thead><tr><th style="text-align:right;">column</th><th style="text-align:right;">description</th></tr></thead><tbody><tr><td style="text-align:right;"><code>matlab_file</code></td><td style="text-align:right;">the <code>.mat</code> file exported by MATLAB&#39;s Camera Calibrator (must contain <code>K</code>, <code>RotationVectors</code>, <code>TranslationVectors</code>, <code>RadialDistortion</code>, and <code>ImageSize</code>; a nested <code>cameraParams</code> struct is handled).</td></tr><tr><td style="text-align:right;"><code>extrinsic_index</code></td><td style="text-align:right;">1-based index of the calibration image whose pose anchors the image ↔ arena mapping — pick the one where the board lies flat on the arena floor.</td></tr></tbody></table><p>Optional: <code>path</code>, <code>center</code>, <code>north</code>, <code>aspect</code> — same meaning as above. Real-world coordinates come out in whatever world units the MATLAB calibration was given (its square size).</p><h2 id="Columns-for-type-apriltag" tabindex="-1">Columns for <code>type = apriltag</code> <a class="header-anchor" href="#Columns-for-type-apriltag" aria-label="Permalink to &quot;Columns for `type = apriltag` {#Columns-for-type-apriltag}&quot;">​</a></h2><p>Required: <code>calibration_id</code>, <code>file</code> (the drone footage — a video where the tags are visible), <code>extrinsic</code> (a timestamp of the frame that establishes the shared reference: <strong>all</strong> the tags must be clearly visible and lie flat on the arena floor there). Optional:</p><table tabindex="0"><thead><tr><th style="text-align:right;">column</th><th style="text-align:right;">default</th><th style="text-align:right;">description</th></tr></thead><tbody><tr><td style="text-align:right;"><code>apriltags</code></td><td style="text-align:right;"><code>4</code></td><td style="text-align:right;">how many tags to expect. The <code>apriltags</code> lowest tag ids seen at <code>extrinsic</code> become the reference set; every run must show those same tags.</td></tr><tr><td style="text-align:right;"><code>family</code></td><td style="text-align:right;"><code>tag36h11</code></td><td style="text-align:right;">the AprilTag family; one of <code>tag36h11</code>, <code>tag25h9</code>, <code>tag16h5</code>.</td></tr><tr><td style="text-align:right;"><code>checker_size</code></td><td style="text-align:right;"><code>12</code></td><td style="text-align:right;">the real-world size of a single tag <strong>cell</strong> (e.g. cm). The black-border square is <code>cells × checker_size</code>, where <code>cells</code> is 8 for <code>tag36h11</code>, 7 for <code>tag25h9</code>, 6 for <code>tag16h5</code>. <strong>Track coordinates come out in this unit.</strong></td></tr><tr><td style="text-align:right;"><code>center</code></td><td style="text-align:right;">—</td><td style="text-align:right;"><code>&quot;(x, y)&quot;</code> pixel of the arena&#39;s origin <strong>in the <code>extrinsic</code> frame</strong>. Becomes the origin of the real-world coordinates.</td></tr><tr><td style="text-align:right;"><code>north</code></td><td style="text-align:right;">—</td><td style="text-align:right;"><code>&quot;(x, y)&quot;</code> pixel due north of <code>center</code> in the <code>extrinsic</code> frame; rotates the coordinates so north is consistent. Requires <code>center</code>.</td></tr><tr><td style="text-align:right;"><code>path</code></td><td style="text-align:right;"><code>.</code></td><td style="text-align:right;">folder containing <code>file</code>, relative to the csv file.</td></tr></tbody></table><p>The tags are stationary across the whole experiment, so the reference is established once here and shared by every run — <code>runs.csv</code> therefore has no <code>apriltags</code> column (and, for an apriltag run, a run&#39;s own <code>start</code> frame is where its target search begins, not the calibration&#39;s <code>center</code>).</p><div class="warning custom-block"><p class="custom-block-title">AprilTags on Apple Silicon Macs</p><p><code>type = apriltag</code> calibrations currently don&#39;t run natively on Apple Silicon (M1/M2/M3/…) Macs — see <a href="/Fromage.jl/dev/help#Macs">the Help page</a> for the workaround.</p></div><h2 id="Mixing-kinds-in-one-file" tabindex="-1">Mixing kinds in one file <a class="header-anchor" href="#Mixing-kinds-in-one-file" aria-label="Permalink to &quot;Mixing kinds in one file {#Mixing-kinds-in-one-file}&quot;">​</a></h2><p>All kinds can be mixed in one file — leave a column blank on the rows where it doesn&#39;t apply:</p><div class="language-csv vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">csv</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">calibration_id,</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">type,</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">file,</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">extrinsic,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">start,</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">stop,</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">checker_size,</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">n_corners,</span><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;">center,</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">north,scale,</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">apriltags,</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">family</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">morning,</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">video,</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">calib_morning.mp4,</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">00:00:02,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">00:00:05,</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">00:00:35,</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">4,</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;(7, 10)&quot;,</span><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;">&quot;(960, 540)&quot;,</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&quot;(960, 100)&quot;,,</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">,</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">afternoon,</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">,</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">calib_afternoon.mp4,</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">1.5,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">5,</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">35,</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">4,</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;(7, 10)&quot;,</span><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;">&quot;(955, 545)&quot;,</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,,</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">,</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">drone,</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">only_scale,</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">drone_shot.mp4,</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">0,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">,</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">,</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">,</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">,</span><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;">&quot;(2000, 1500)&quot;,</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,0.21,</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">,</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flight,</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">apriltag,</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">drone_flight.mp4,</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">00:00:04,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">,</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">,</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">12,</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">,</span><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;">&quot;(960, 540)&quot;,</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&quot;(960, 100)&quot;,,</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">4,</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tag36h11</span></span></code></pre></div><h2 id="Next" tabindex="-1">Next <a class="header-anchor" href="#Next" aria-label="Permalink to &quot;Next {#Next}&quot;">​</a></h2><ul><li><a href="./results">Your results →</a></li></ul>',33)])])}const k=e(s,[["render",r]]);export{p as __pageData,k as default};
